import { ParameterValue } from "@/commandly/lib/types/flat";
import { Command, Tool } from "@/commandly/lib/types/flat";
import { ParameterRenderContext, ParameterRendererEntry } from "@/commandly/lib/types/renderer";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { InfoIcon } from "lucide-react";
import React from "react";

const findDefaultCommand = (tool: Tool): Command | null => {
  const defaultCommand = tool.commands.find((command) => command.isDefault);
  if (defaultCommand) return defaultCommand;

  const nameMatchCommand = tool.commands.find(
    (command) => command.name.toLowerCase() === tool.name.toLowerCase(),
  );
  if (nameMatchCommand) return nameMatchCommand;

  return tool.commands.length > 0 ? tool.commands[0] : null;
};

interface ParameterLabelProps {
  name: string;
  longFlag?: string;
  shortFlag?: string;
  isRequired?: boolean;
  isGlobal?: boolean;
  description?: string;
  className?: string;
  children?: React.ReactNode;
}

function ParameterLabel({
  name,
  longFlag,
  shortFlag,
  isRequired,
  isGlobal,
  description,
  className,
  children,
}: ParameterLabelProps) {
  return (
    <Label className={className}>
      {name}
      {(longFlag || shortFlag) && (
        <span className="ml-1 text-muted-foreground">
          ({[longFlag, shortFlag].filter(Boolean).join(", ")})
        </span>
      )}
      {isRequired && <span className="ml-1 text-destructive">*</span>}
      <Tooltip>
        <TooltipTrigger>
          <InfoIcon className="h-3.5 w-3.5" />
        </TooltipTrigger>
        <TooltipContent>
          <span>{description}</span>
        </TooltipContent>
      </Tooltip>
      {children}
      {isGlobal && (
        <Badge
          variant="outline"
          className="ml-2 text-xs"
        >
          global
        </Badge>
      )}
    </Label>
  );
}

function FlagInput({ parameter, value, onUpdate }: ParameterRenderContext) {
  return (
    <div className="flex items-center space-x-2">
      <Switch
        checked={value === "true" || value === true}
        onCheckedChange={onUpdate}
      />
      <ParameterLabel
        className="flex-1 select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
    </div>
  );
}

function OptionEnumInput({ parameter, value, onUpdate }: ParameterRenderContext) {
  return (
    <div className="space-y-2">
      <ParameterLabel
        className="select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
      <Select
        value={value as string}
        onValueChange={onUpdate}
      >
        <SelectTrigger>
          <SelectValue placeholder="Select an option" />
        </SelectTrigger>
        <SelectContent>
          {parameter.enum?.values?.map((enumValue) => (
            <SelectItem
              key={enumValue.value}
              value={enumValue.value}
            >
              {enumValue.displayName || enumValue.value}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
    </div>
  );
}

function OptionBooleanInput({ parameter, value, onUpdate }: ParameterRenderContext) {
  return (
    <div className="flex items-center space-x-2">
      <Switch
        checked={value === "true" || value === true}
        onCheckedChange={(checked) => onUpdate(checked.toString())}
      />
      <ParameterLabel
        className="flex-1 select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
    </div>
  );
}

function OptionTextInput({ parameter, value, onUpdate }: ParameterRenderContext) {
  return (
    <div className="space-y-2">
      <ParameterLabel
        className="flex-1 select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
      <Input
        type={parameter.dataType === "Number" ? "number" : "text"}
        value={parameter.dataType === "Number" ? (value as number) : (value as string)}
        onChange={(e) => onUpdate(e.target.value)}
        placeholder="Enter value"
      />
    </div>
  );
}

function ArgumentInput({ parameter, value, onUpdate }: ParameterRenderContext) {
  return (
    <div className="space-y-2">
      <ParameterLabel
        name={parameter.name}
        isRequired={parameter.isRequired}
        description={parameter.description}
      >
        <Badge
          variant="secondary"
          className="ml-2 text-xs"
        >
          {parameter.parameterType}
          {parameter.position !== undefined && ` (${parameter.position})`}
        </Badge>
      </ParameterLabel>
      <Input
        type={parameter.dataType === "Number" ? "number" : "text"}
        value={parameter.dataType === "Number" ? (value as number) : (value as string)}
        onChange={(e) => onUpdate(e.target.value)}
        placeholder="Enter value"
      />
    </div>
  );
}

export function defaultComponents(): ParameterRendererEntry[] {
  return [
    { condition: (p) => p.parameterType === "Flag", component: (ctx) => <FlagInput {...ctx} /> },
    {
      condition: (p) => p.parameterType === "Argument",
      component: (ctx) => <ArgumentInput {...ctx} />,
    },
    {
      condition: (p) => p.parameterType === "Option" && p.dataType === "Enum",
      component: (ctx) => <OptionEnumInput {...ctx} />,
    },
    {
      condition: (p) => p.parameterType === "Option" && p.dataType === "Boolean",
      component: (ctx) => <OptionBooleanInput {...ctx} />,
    },
    {
      condition: (p) => p.parameterType === "Option",
      component: (ctx) => <OptionTextInput {...ctx} />,
    },
  ];
}

interface ToolRendererProps {
  selectedCommand?: Command | null;
  tool: Tool;
  catalog?: ParameterRendererEntry[];
  parameterValues: Record<string, ParameterValue>;
  updateParameterValue: (parameterKey: string, value: ParameterValue) => void;
}

export function ToolRenderer({
  selectedCommand: providedCommand,
  tool,
  catalog = defaultComponents(),
  parameterValues,
  updateParameterValue,
}: ToolRendererProps) {
  const selectedCommand = providedCommand ?? findDefaultCommand(tool);

  return (
    <React.Fragment>
      {selectedCommand && tool.commands.length === 0 ? (
        <p className="text-sm text-muted-foreground">No commands available for this tool.</p>
      ) : (
        <div className="space-y-4">
          {tool.parameters.length > 0 ? (
            tool.parameters
              .filter((param) => param.commandKey === selectedCommand?.key || param.isGlobal)
              .map((parameter) => {
                const value = parameterValues[parameter.key] || "";
                const onUpdate = (val: ParameterValue) => updateParameterValue(parameter.key, val);
                const entry = catalog.find((e) => e.condition(parameter));
                return entry ? (
                  <React.Fragment key={parameter.key}>
                    {entry.component({ parameter, value, onUpdate })}
                  </React.Fragment>
                ) : null;
              })
          ) : (
            <p className="text-sm text-muted-foreground">
              No parameters available for this command.
            </p>
          )}
        </div>
      )}
    </React.Fragment>
  );
}

import type { Parameter, ParameterValue } from "@/commandly/lib/types/flat";
import type { ReactElement } from "react";

export type ParameterRenderContext = {
  parameter: Parameter;
  value: ParameterValue;
  onUpdate: (value: ParameterValue) => void;
};

export type ParameterRendererEntry = {
  condition: (parameter: Parameter) => boolean;
  component: (context: ParameterRenderContext) => ReactElement | null;
};

export interface ToolInfo {
  description?: string;
  version?: string;
  url?: string;
}

export interface Command {
  key: string;
  parentCommandKey?: string;
  name: string;
  description?: string;
  interactive?: boolean;
  isDefault?: boolean;
  sortOrder?: number;
}

export interface ParameterEnumValue {
  value: string;
  displayName: string;
  description?: string;
  isDefault?: boolean;
  sortOrder?: number;
}

export interface ParameterEnumValues {
  values: ParameterEnumValue[];
  allowMultiple?: boolean;
  separator?: string;
}

export type ParameterValidationType =
  | "min_length"
  | "max_length"
  | "min_value"
  | "max_value"
  | "regex";

export interface ParameterValidation {
  key: string;
  validationType: ParameterValidationType;
  validationValue: string;
  errorMessage: string;
}

export type ParameterDependencyType = "requires" | "conflicts_with";

export interface ParameterDependency {
  key: string;
  parameterKey: string;
  dependsOnParameterKey: string;
  dependencyType: ParameterDependencyType;
  conditionValue?: string;
}

export type ParameterValue = string | number | boolean;

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface ToolMetadata {}

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface ParameterMetadata {
  tags?: string[];
}

export type ParameterType = "Flag" | "Option" | "Argument";

export type ParameterDataType = "String" | "Number" | "Boolean" | "Enum";

export interface Parameter {
  key: string;
  name: string;
  commandKey?: string;
  description?: string;
  group?: string;
  metadata?: ParameterMetadata;
  parameterType: ParameterType;
  dataType: ParameterDataType;
  isRequired?: boolean;
  isRepeatable?: boolean;
  isGlobal?: boolean;
  shortFlag?: string;
  longFlag?: string;
  position?: number;
  sortOrder?: number;
  arraySeparator?: string;
  keyValueSeparator?: string;
  enum?: ParameterEnumValues;
  validations?: ParameterValidation[];
  dependencies?: ParameterDependency[];
}

export type ExclusionType = "mutual_exclusive" | "required_one_of";

export interface ExclusionGroup {
  key?: string;
  commandKey?: string;
  name: string;
  exclusionType: ExclusionType;
  parameterKeys: string[];
}

export interface Tool {
  name: string;
  displayName: string;
  info?: ToolInfo;
  commands: Command[];
  parameters: Parameter[];
  exclusionGroups?: ExclusionGroup[];
  metadata?: ToolMetadata;
}

import type {
  ExclusionType,
  ParameterDataType,
  ParameterDependencyType,
  ParameterEnumValues,
  ParameterMetadata,
  ParameterType,
  ParameterValidationType,
  ToolInfo,
  ToolMetadata,
} from "@/commandly/lib/types/flat";

export interface NestedParameterValidation {
  validationType: ParameterValidationType;
  validationValue: string;
  errorMessage: string;
}

export interface NestedParameterDependency {
  dependsOnParameter: string;
  dependencyType: ParameterDependencyType;
  conditionValue?: string;
}

export interface NestedParameter {
  name: string;
  description?: string;
  group?: string;
  parameterType: ParameterType;
  dataType: ParameterDataType;
  metadata?: ParameterMetadata;
  isRequired?: boolean;
  isRepeatable?: boolean;
  isGlobal?: boolean;
  shortFlag?: string;
  longFlag?: string;
  position?: number;
  sortOrder?: number;
  arraySeparator?: string;
  keyValueSeparator?: string;
  enum?: ParameterEnumValues;
  validations?: NestedParameterValidation[];
  dependencies?: NestedParameterDependency[];
}

export interface NestedCommand {
  name: string;
  description?: string;
  interactive?: boolean;
  isDefault: boolean;
  sortOrder: number;
  parameters: NestedParameter[];
  subcommands: NestedCommand[];
}

export interface NestedExclusionGroup {
  name: string;
  exclusionType: ExclusionType;
  parameters: string[];
}

export interface NestedTool {
  $schema?: string;
  name: string;
  displayName: string;
  info?: ToolInfo;
  url?: string;
  globalParameters: NestedParameter[];
  commands: NestedCommand[];
  exclusionGroups?: NestedExclusionGroup[] | null;
  metadata?: ToolMetadata;
}
